class Solution:
    def findAllRecipes(self, recipes, ingredients, supplies):
        available = set(supplies)
        made = set()
        idx = {r: i for i, r in enumerate(recipes)}
        changed = True
        while changed:
            changed = False
            for r in recipes:
                if r in made:
                    continue
                ings = ingredients[idx[r]]
                if all(ing in available or ing in made for ing in ings):
                    made.add(r)
                    available.add(r)
                    changed = True
        return sorted(made)

