from collections import deque

class Solution:
    def findAllRecipes(self, recipes, ingredients, supplies):
        recipe_set = set(recipes)
        supply_set = set(supplies)
        indegree = {r: 0 for r in recipes}
        graph = {r: [] for r in recipes}
        makeable = {r: True for r in recipes}
        for i, r in enumerate(recipes):
            for ing in ingredients[i]:
                if ing in recipe_set:
                    indegree[r] += 1
                    graph[ing].append(r)
                elif ing not in supply_set:
                    makeable[r] = False
        queue = deque(r for r in recipes if indegree[r] == 0 and makeable[r])
        result = []
        while queue:
            r = queue.popleft()
            result.append(r)
            for nxt in graph[r]:
                indegree[nxt] -= 1
                if indegree[nxt] == 0 and makeable[nxt]:
                    queue.append(nxt)
        return sorted(result)

