var findAllRecipes = function(recipes, ingredients, supplies) {
    const recipeSet = new Set(recipes);
    const supplySet = new Set(supplies);
    const indegree = {};
    const graph = {};
    const makeable = {};
    recipes.forEach(r => { indegree[r] = 0; graph[r] = []; makeable[r] = true; });
    for (let i = 0; i < recipes.length; i++) {
        const r = recipes[i];
        for (const ing of ingredients[i]) {
            if (recipeSet.has(ing)) {
                indegree[r]++;
                graph[ing].push(r);
            } else if (!supplySet.has(ing)) {
                makeable[r] = false;
            }
        }
    }
    const queue = [];
    for (const r of recipes) {
        if (indegree[r] === 0 && makeable[r]) queue.push(r);
    }
    const result = [];
    let head = 0;
    while (head < queue.length) {
        const r = queue[head++];
        result.push(r);
        for (const nxt of graph[r]) {
            indegree[nxt]--;
            if (indegree[nxt] === 0 && makeable[nxt]) queue.push(nxt);
        }
    }
    result.sort();
    return result;
};
